import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        class DSU {
            private int[] parent;
            private int[] rank;
            private int count;

            public DSU(int size) {
                parent = new int[size];
                rank = new int[size];
                for (int i = 0; i < size; i++) {
                    parent[i] = i;
                    rank[i] = 1;
                }
                count = size;
            }

            public void union(int x, int y) {
                int xRoot = find(x);
                int yRoot = find(y);
                if (xRoot == yRoot) return;
                if (rank[xRoot] < rank[yRoot]) {
                    parent[xRoot] = yRoot;
                } else {
                    parent[yRoot] = xRoot;
                    if (rank[xRoot] == rank[yRoot]) {
                        rank[xRoot]++;
                    }
                }
                count--;
            }

            public int find(int x) {
                if (parent[x] != x) {
                    parent[x] = find(parent[x]);
                }
                return parent[x];
            }

            public int getComponentCount() {
                return count;
            }
        }

        List<long[]> sortedEdges = new ArrayList<>();
        for (long[] e : edges) {
            sortedEdges.add(e);
        }
        Collections.sort(sortedEdges, (a, b) -> Long.compare(a[2], b[2]));

        long maxWeight = 0;
        for (long[] e : sortedEdges) {
            maxWeight = Math.max(maxWeight, e[2]);
        }

        long low = 0, high = maxWeight;
        long answer = maxWeight;

        while (low <= high) {
            long mid = (low + high) / 2;
