            for (long[] e : sortedEdges) {
                if (e[2] <= mid) {
                    dsu.union((int) e[0], (int) e[1]);
                }
            }
            int components = dsu.getComponentCount();
            if (components <= k) {
                answer = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        return answer;
    }
}
