import java.util.Arrays;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        Arrays.sort(edges, (a, b) -> Long.compare(a[2], b[2]));
        long maxW = 0;
        for (long[] e : edges) {
            maxW = Math.max(maxW, e[2]);
        }
        long low = 0, high = maxW;
        while (low < high) {
            long mid = (low + high) / 2;
            if (isPossible(n, edges, mid, k)) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }

    private static boolean isPossible(long n, long[][] edges, long mid, long k) {
        int[] parent = new int[(int) n];
        int[] rank = new int[(int) n];
        int count = (int) n;
        for (int i = 0; i < (int) n; i++) {
            parent[i] = i;
            rank[i] = 1;
        }
        for (long[] e : edges) {
            if (e[2] <= mid) {
                int u = (int) e[0];
                int v = (int) e[1];
                int rootU = find(parent, u);
                int rootV = find(parent, v);
                if (rootU != rootV) {
                    if (rank[rootU] < rank[rootV]) {
                        parent[rootU] = rootV;
                    } else {
                        parent[rootV] = rootU;
                        if (rank[rootU] == rank[rootV]) {
                            rank[rootU]++;
                        }
                    }
                    count--;
                }
            }
        }
        return count <= k;
    }

    private static int find(int[] parent, int x) {
        if (parent[x] != x) {
            parent[x] = find(parent, parent[x]);
        }
        return parent[x];
    }
}
